#include<bits/stdc++.h>
using namespace std;
int n;
int a[4],b[4];
int cmp(int a[],int b[]){
	int A=0,B=0;
	for(int i=0;i<4;i++){
		for(int j=0;j<4;j++){
			if(a[i]>b[j]){
				A++;
			}
			if(a[i]<b[j]){
				B++;
			}
		}
	}
	if(A>B)return 1;
	if(A<B)return -1;
	return 0;
}
int main()
{	
	cin>>n;
	for(int i=0;i<n;i++){
		cin>>a[0]>>a[1]>>a[2]>>a[3];
		cin>>b[0]>>b[1]>>b[2]>>b[3];
		int a_b=cmp(a,b);
		if(a_b==0){
			cout<<"no"<<endl;
			continue;
		}
		if(a_b==-1){
			swap(a[0],b[0]);
			swap(a[2],b[2]);
			swap(a[3],b[3]);
			swap(a[1],b[1]);
		}
		bool flag=true;
		for(int j=1;j<=10&&flag;j++){
			for(int k=1;k<=10&&flag;k++){
				for(int l=1;l<=10&&flag;l++){
					for(int m=1;m<=10&&flag;m++){
						int c[4]={j,k,l,m};
						int b_c=cmp(b,c);
						int c_a=cmp(c,a);
						if(b_c==1&&c_a==1){
							cout<<"yes"<<endl;
							flag=false;
							break;
						}
					}
				}
			}
		}
		if(flag){
			cout<<"no"<<endl;
		}
	}		
}
